"use client";

import { useState } from "react";
import { submitFeedback } from "@/lib/api";

type BucketType = "decision" | "commitment" | "discussion" | "open_question";

const BUCKET_COLORS: Record<BucketType, string> = {
  decision: "bg-teal-500/10 border-teal-500/30 text-teal-400",
  commitment: "bg-amber-500/10 border-amber-500/30 text-amber-400",
  discussion: "bg-slate-500/10 border-slate-500/30 text-slate-400",
  open_question: "bg-rose-500/10 border-rose-500/30 text-rose-400",
};

const BUCKET_LABELS: Record<BucketType, string> = {
  decision: "Decisions",
  commitment: "Commitments",
  discussion: "Discussions",
  open_question: "Open Questions",
};

export default function BucketView({ utterances, meetingId }: { utterances: any[], meetingId: string }) {
  const [activeTab, setActiveTab] = useState<BucketType>("decision");
  const [editingId, setEditingId] = useState<number | null>(null);

  // Group by bucket — use flat utterance_type field from API
  const buckets = utterances.reduce((acc, u) => {
    const type = u.utterance_type || "discussion";
    if (!acc[type]) acc[type] = [];
    acc[type].push(u);
    return acc;
  }, {} as Record<string, any[]>);

  const handleCorrect = async (u: any, newType: BucketType) => {
    try {
      await submitFeedback({
        meeting_id: meetingId,
        utterance_text: u.text,
        original_type: u.utterance_type,
        corrected_type: newType,
      });
    } catch (err) {
      console.error(err);
    }
    setEditingId(null);
  };

  const currentItems = buckets[activeTab] || [];

  return (
    <div className="glass rounded-2xl p-6 border border-white/10 shadow-xl mt-8">
      <div className="flex gap-2 overflow-x-auto pb-4 mb-6 border-b border-slate-700/50 hide-scrollbar">
        {(Object.keys(BUCKET_LABELS) as BucketType[]).map((type) => (
          <button
            key={type}
            onClick={() => setActiveTab(type)}
            className={`px-5 py-2.5 rounded-xl font-medium text-sm whitespace-nowrap transition-all duration-300 ${
              activeTab === type 
                ? `${BUCKET_COLORS[type].split(" ")[0]} border ${BUCKET_COLORS[type].split(" ")[1]} text-white shadow-lg` 
                : "bg-slate-800/50 text-slate-400 hover:text-white hover:bg-slate-700/50 border border-transparent"
            }`}
          >
            {BUCKET_LABELS[type]} <span className="ml-2 bg-black/20 px-2 py-0.5 rounded-md text-xs">{buckets[type]?.length || 0}</span>
          </button>
        ))}
      </div>

      <div className="space-y-4">
        {currentItems.length === 0 ? (
          <p className="text-slate-500 text-center py-8">No {BUCKET_LABELS[activeTab].toLowerCase()} found in this meeting.</p>
        ) : (
          currentItems.map((u: any, idx: number) => (
            <div key={idx} className="bg-slate-800/40 border border-slate-700/50 rounded-xl p-4 flex flex-col gap-3 group hover:border-slate-600 transition-colors">
              <div className="flex justify-between items-start">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-full bg-gradient-to-br from-slate-600 to-slate-800 flex items-center justify-center text-xs font-bold text-white shadow-inner">
                    {u.speaker?.charAt(0)?.toUpperCase() || "?"}
                  </div>
                  <span className="font-semibold text-slate-200">{u.speaker}</span>
                </div>
                <span className={`text-xs px-2 py-1 rounded-md border ${BUCKET_COLORS[(u.utterance_type || "discussion") as BucketType]}`}>
                  {Math.round((u.classification_confidence || 0) * 100)}% Match
                </span>
              </div>
              
              <p className="text-slate-300 text-[15px] leading-relaxed pl-11">"{u.text}"</p>

              {u.reasoning && (
                <p className="text-slate-500 text-xs pl-11 italic">💡 {u.reasoning}</p>
              )}
              
              <div className="pl-11 mt-1 flex items-center gap-2 relative">
                <button 
                  onClick={() => setEditingId(editingId === idx ? null : idx)}
                  className="text-xs text-slate-500 hover:text-slate-300 flex items-center gap-1 transition-colors"
                >
                  <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                  </svg>
                  Correct this
                </button>
                
                {editingId === idx && (
                  <div className="absolute top-6 left-11 z-20 bg-slate-800 border border-slate-700 p-2 rounded-xl shadow-2xl flex flex-col gap-1 w-48">
                    <span className="text-xs font-medium text-slate-400 px-2 py-1">Reassign to:</span>
                    {(Object.keys(BUCKET_LABELS) as BucketType[]).filter(t => t !== u.utterance_type).map(type => (
                      <button
                        key={type}
                        onClick={() => handleCorrect(u, type)}
                        className="text-left text-sm px-3 py-1.5 rounded-lg hover:bg-slate-700/50 transition-colors text-slate-300"
                      >
                        {BUCKET_LABELS[type]}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
