"use client";

import React, { useState } from "react";
import { pushTaskToNotion, pushTaskToLinear } from "@/lib/api";

const PRIORITY_COLORS = {
  high: "bg-rose-500/10 border-rose-500/30 text-rose-400",
  medium: "bg-amber-500/10 border-amber-500/30 text-amber-400",
  low: "bg-emerald-500/10 border-emerald-500/30 text-emerald-400",
};

export default function TaskList({ tasks }: { tasks: any[] }) {
  const [loadingAction, setLoadingAction] = useState<{id: number, type: string} | null>(null);
  const [success, setSuccess] = useState<Record<number, Record<string, boolean>>>({});

  const handlePush = async (task: any, idx: number, type: "notion" | "linear") => {
    setLoadingAction({ id: idx, type });
    try {
      if (type === "notion") {
        await pushTaskToNotion(task);
      } else {
        await pushTaskToLinear(task);
      }
      setSuccess((prev) => ({
        ...prev,
        [idx]: { ...(prev[idx] || {}), [type]: true }
      }));
    } catch (err) {
      console.error(`Failed to push to ${type}:`, err);
      alert(`Failed to push to ${type}. Did you configure API keys?`);
    } finally {
      setLoadingAction(null);
    }
  };

  if (!tasks || tasks.length === 0) {
    return (
      <div className="glass rounded-2xl p-8 text-center mt-8 cursor-default">
        <h3 className="text-xl font-semibold text-slate-300 mb-2">No tasks extracted</h3>
        <p className="text-slate-500">We didn't find any explicit commitments or action items in this meeting.</p>
      </div>
    );
  }

  return (
    <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6 mt-6">
      {tasks.map((task, idx) => {
        const notionSuccess = success[idx]?.notion || task.notion_page_id;
        const linearSuccess = success[idx]?.linear || task.linear_issue_id;
        
        return (
          <div key={idx} className="bg-slate-800/40 p-6 rounded-2xl flex flex-col border border-slate-700/50 hover:border-purple-500/30 transition-all duration-300 shadow-lg group relative overflow-hidden">
            <div className="absolute top-0 right-0 p-24 bg-purple-500/5 rounded-full blur-3xl -mr-12 -mt-12 transition-all duration-500 group-hover:scale-150 pointer-events-none" />
            
            <div className="flex justify-between items-start mb-4 relative z-10">
              <h3 className="text-lg font-bold text-white leading-tight pr-4">{task.title}</h3>
              <span className={`px-2 py-1 text-[10px] font-bold uppercase tracking-wider rounded-md border whitespace-nowrap ${PRIORITY_COLORS[task.priority as keyof typeof PRIORITY_COLORS] || PRIORITY_COLORS.medium}`}>
                {task.priority || "Medium"}
              </span>
            </div>

            <div className="flex items-center gap-4 mb-5 relative z-10">
              <div className="flex items-center gap-2">
                <div className="w-7 h-7 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-xs font-bold text-white shadow-inner">
                  {task.owner ? task.owner.charAt(0).toUpperCase() : "?"}
                </div>
                <span className="text-sm font-medium text-slate-300">{task.owner || "Unassigned"}</span>
              </div>
              
              <div className="flex items-center gap-1.5 text-xs text-slate-400">
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                </svg>
                {task.deadline || "No deadline"}
              </div>
            </div>

            <blockquote className="border-l-[3px] border-purple-500/30 pl-4 py-2 my-auto text-sm italic text-slate-400 relative z-10 bg-slate-900/30 rounded-r-lg line-clamp-3">
              "{task.context_quote}"
            </blockquote>

            <div className="flex gap-3 relative z-10 pt-5 mt-4 border-t border-slate-700/50">
              <button 
                onClick={() => handlePush(task, idx, "notion")}
                disabled={notionSuccess || (loadingAction?.id === idx && loadingAction.type === "notion")}
                className={`flex-1 py-2 rounded-lg text-xs font-semibold transition-colors border flex items-center justify-center gap-2 
                  ${notionSuccess 
                    ? 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30 cursor-default' 
                    : 'bg-slate-800 hover:bg-slate-700 text-slate-300 border-slate-700/50'}`}
              >
                {loadingAction?.id === idx && loadingAction.type === "notion" ? (
                  <span className="animate-pulse">Pushing...</span>
                ) : notionSuccess ? (
                  <>
                    <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                    Pushed
                  </>
                ) : (
                  <>
                    <svg className="w-3.5 h-3.5" viewBox="0 0 24 24" fill="currentColor"><path d="M4.459 4.208c.745-.636 1.761-1.002 2.871-1.002 1.11 0 2.126.366 2.871 1.002.745.636 1.205 1.517 1.205 2.5v10.584c0 .983-.46 1.864-1.205 2.5-.745.636-1.761 1.002-2.871 1.002-1.11 0-2.126-.366-2.871-1.002-.745-.636-1.205-1.517-1.205-2.5V6.708c0-.983.46-1.864 1.205-2.5zm10.74 0c-.745-.636-1.761-1.002-2.871-1.002-1.11 0-2.126.366-2.871 1.002-.745.636-1.205 1.517-1.205 2.5v10.584c0 .983.46 1.864 1.205 2.5.745.636 1.761 1.002 2.871 1.002 1.11 0 2.126-.366 2.871-1.002.745-.636 1.205-1.517 1.205-2.5V6.708c0-.983-.46-1.864-1.205-2.5z"/></svg>
                    Notion
                  </>
                )}
              </button>
              
              <button 
                onClick={() => handlePush(task, idx, "linear")}
                disabled={linearSuccess || (loadingAction?.id === idx && loadingAction.type === "linear")}
                className={`flex-1 py-2 rounded-lg text-xs font-semibold transition-colors border flex items-center justify-center gap-2 
                  ${linearSuccess 
                    ? 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30 cursor-default' 
                    : 'bg-indigo-500/10 hover:bg-indigo-500/20 text-indigo-400 border-indigo-500/20'}`}
              >
                {loadingAction?.id === idx && loadingAction.type === "linear" ? (
                  <span className="animate-pulse">Pushing...</span>
                ) : linearSuccess ? (
                  <>
                    <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                    Tracking
                  </>
                ) : (
                  <>
                    Linear Issue
                  </>
                )}
              </button>
            </div>
          </div>
        );
      })}
    </div>
  );
}
